+// ReloadStatusData describes the result of one transactional configuration reload.
+type ReloadStatusData struct {
+	LastReloadID        string           `json:"last_reload_id"`
+	LastReloadSuccessful bool             `json:"last_reload_successful"`
+	ErrorCategory       string           `json:"error_category"`
+	ErrorMessage        string           `json:"error_message"`
+	AppliedReloaders    []string         `json:"applied_reloaders"`
+	RollbackAttempted   bool             `json:"rollback_attempted"`
+	RollbackSuccessful  bool             `json:"rollback_successful"`
+	FailedReloader      string           `json:"failed_reloader"`
+	ReloaderTimingsMS   map[string]int64 `json:"reloader_timings_ms"`
+}
+
+// ReloadStatus stores the most recent transactional reload result.
+type ReloadStatus struct {
+	mu   sync.RWMutex
+	path string
+	data ReloadStatusData
+}
+
+func emptyReloadStatus() ReloadStatusData {
+	return ReloadStatusData{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
+}
+
+// NewReloadStatus initializes a status store. Missing or invalid persisted state is ignored.
+func NewReloadStatus(path string) *ReloadStatus {
+	s := &ReloadStatus{path: path, data: emptyReloadStatus()}
+	if path == "" {
+		return s
+	}
+	b, err := os.ReadFile(path)
+	if err != nil {
+		return s
+	}
+	var data ReloadStatusData
+	if json.Unmarshal(b, &data) != nil || !validReloadStatus(data) {
+		return s
+	}
+	if data.AppliedReloaders == nil {
+		data.AppliedReloaders = []string{}
+	}
+	if data.ReloaderTimingsMS == nil {
+		data.ReloaderTimingsMS = map[string]int64{}
+	}
+	s.data = data
+	return s
+}
+
+func validReloadStatus(data ReloadStatusData) bool {
+	switch data.ErrorCategory {
+	case "none", "load_error", "apply_error", "rollback_error":
+		return true
+	default:
+		return false
+	}
+}
+
+// Set records and atomically persists a reload outcome. Persistence failures do not affect reloads.
+func (s *ReloadStatus) Set(data ReloadStatusData) {
+	if data.AppliedReloaders == nil {
+		data.AppliedReloaders = []string{}
+	}
+	if data.ReloaderTimingsMS == nil {
+		data.ReloaderTimingsMS = map[string]int64{}
+	}
+	s.mu.Lock()
+	s.data = data
+	path := s.path
+	s.mu.Unlock()
+	if path == "" {
+		return
+	}
+	b, err := json.Marshal(data)
+	if err != nil {
+		return
+	}
+	tmp := path + ".tmp"
+	if os.WriteFile(tmp, b, 0o644) == nil {
+		_ = os.Rename(tmp, path)
+	}
+}
+
+// Get returns a copy of the current status.
+func (s *ReloadStatus) Get() ReloadStatusData {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	d := s.data
+	d.AppliedReloaders = append([]string(nil), d.AppliedReloaders...)
+	d.ReloaderTimingsMS = make(map[string]int64, len(d.ReloaderTimingsMS))
+	for k, v := range s.data.ReloaderTimingsMS {
+		d.ReloaderTimingsMS[k] = v
+	}
+	return d
+}
+
+func (h *Handler) serveReloadStatus(w http.ResponseWriter, _ *http.Request) {
+	w.Header().Set("Content-Type", "application/json")
+	_ = json.NewEncoder(w).Encode(struct {
+		Status string           `json:"status"`
+		Data   ReloadStatusData `json:"data"`
+	}{Status: "success", Data: h.options.ReloadStatus.Get()})
+}
+
+// NewReloadStatusForTSDB creates a status store in the TSDB directory.
+func NewReloadStatusForTSDB(tsdbDir string) *ReloadStatus {
+	return NewReloadStatus(filepath.Join(tsdbDir, "reload-status.json"))
+}
+
+// NewReloadOutcome creates a timestamped outcome.
+func NewReloadOutcome() ReloadStatusData {
+	d := emptyReloadStatus()
+	d.LastReloadID = time.Now().UTC().Format(time.RFC3339)
+	return d
+}
