+// reloadConfigTransactional applies reloaders in order and restores the previous
+// fully applied configuration if a later reloader fails.
+func reloadConfigTransactional(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), status *web.ReloadStatus, lastKnownGood **config.Config, recordOutcome bool, rls ...reloader) (err error) {
+	start := time.Now()
+	var outcome web.ReloadStatusData
+	if recordOutcome {
+		outcome = web.NewReloadOutcome()
+	}
+	defer func() {
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			callback(true)
+		} else {
+			configSuccess.Set(0)
+			callback(false)
+		}
+		if recordOutcome {
+			status.Set(outcome)
+		}
+	}()
+
+	logger.Info("Loading configuration file", "filename", filename)
+	conf, err := config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		if recordOutcome {
+			outcome.ErrorCategory = "load_error"
+			outcome.ErrorMessage = err.Error()
+		}
+		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	applied := make([]reloader, 0, len(rls))
+	for _, rl := range rls {
+		rstart := time.Now()
+		applyErr := rl.reloader(conf)
+		if recordOutcome {
+			outcome.ReloaderTimingsMS[rl.name] = durationToInt64Millis(time.Since(rstart))
+		}
+		if applyErr != nil {
+			if recordOutcome {
+				outcome.ErrorCategory = "apply_error"
+				outcome.ErrorMessage = applyErr.Error()
+				outcome.FailedReloader = rl.name
+				outcome.AppliedReloaders = append(outcome.AppliedReloaders, reloaderNames(applied)...)
+			}
+			if len(applied) > 0 && *lastKnownGood != nil {
+				if recordOutcome {
+					outcome.RollbackAttempted = true
+					outcome.RollbackSuccessful = true
+				}
+				for _, rollback := range rls {
+					if rollbackErr := rollback.reloader(*lastKnownGood); rollbackErr != nil {
+						if recordOutcome {
+							outcome.ErrorCategory = "rollback_error"
+							outcome.ErrorMessage = fmt.Sprintf("apply failed in %s: %v; rollback failed in %s: %v", rl.name, applyErr, rollback.name, rollbackErr)
+							outcome.RollbackSuccessful = false
+						}
+						return fmt.Errorf("applying configuration failed in %s: %w (rollback failed in %s: %v)", rl.name, applyErr, rollback.name, rollbackErr)
+					}
+				}
+			}
+			return fmt.Errorf("applying configuration failed in %s: %w", rl.name, applyErr)
+		}
+		applied = append(applied, rl)
+	}
+
+	*lastKnownGood = conf
+	if recordOutcome {
+		outcome.LastReloadSuccessful = true
+		outcome.ErrorCategory = "none"
+		outcome.AppliedReloaders = reloaderNames(applied)
+	}
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	logger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
+	return nil
+}
+
+func reloaderNames(rls []reloader) []string {
+	names := make([]string, 0, len(rls))
+	for _, rl := range rls {
+		names = append(names, rl.name)
+	}
+	return names
+}
